Ecco un'implementazione completa in Go di un servizio HTTP con tutte le caratteristiche richieste:

```go
package main

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/signal"
	"sync"
	"sync/atomic"
	"syscall"
	"time"
)

// Metrics raccoglie le metriche di base del servizio
type Metrics struct {
	mu          sync.RWMutex
	requests    int64
	errors      int64
	latency     time.Duration
	lastLatency time.Duration
}

func (m *Metrics) RecordRequest(duration time.Duration, hasError bool) {
	atomic.AddInt64(&m.requests, 1)
	if hasError {
		atomic.AddInt64(&m.errors, 1)
	}
	m.mu.Lock()
	m.latency = duration
	m.lastLatency = duration
	m.mu.Unlock()
}

func (m *Metrics) Snapshot() map[string]interface{} {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return map[string]interface{}{
		"requests":    atomic.LoadInt64(&m.requests),
		"errors":      atomic.LoadInt64(&m.errors),
		"last_latency": m.lastLatency.String(),
	}
}

// WorkerPool gestisce un pool di worker con context cancellation
type WorkerPool struct {
	workers    int
	tasks      chan func(context.Context)
	cancelFunc context.CancelFunc
	ctx        context.Context
	wg         sync.WaitGroup
}

func NewWorkerPool(workers int) *WorkerPool {
	ctx, cancel := context.WithCancel(context.Background())
	wp := &WorkerPool{
		workers:    workers,
		tasks:      make(chan func(context.Context), 100),
		cancelFunc: cancel,
		ctx:        ctx,
	}
	wp.start()
	return wp
}

func (wp *WorkerPool) start() {
	for i := 0; i < wp.workers; i++ {
		wp.wg.Add(1)
		go func(id int) {
			defer wp.wg.Done()
			for {
				select {
				case task, ok := <-wp.tasks:
					if !ok {
						return
					}
					task(wp.ctx)
				case <-wp.ctx.Done():
					return
				}
			}
		}(i)
	}
}

func (wp *WorkerPool) Submit(task func(context.Context)) error {
	select {
	case wp.tasks <- task:
		return nil
	case <-wp.ctx.Done():
		return errors.New("worker pool chiuso")
	default:
		return errors.New("coda piena")
	}
}

func (wp *WorkerPool) Shutdown() {
	wp.cancelFunc()
	close(wp.tasks)
	wp.wg.Wait()
}

// Server gestisce il server HTTP con graceful shutdown
type Server struct {
	httpServer *http.Server
	workerPool *WorkerPool
	metrics    *Metrics
}

func NewServer(addr string, workers int) *Server {
	metrics := &Metrics{}
	wp := NewWorkerPool(workers)

	mux := http.NewServeMux()
	mux.HandleFunc("/api/work", metrics.Middleware(wp.Middleware(handleWork)))
	mux.HandleFunc("/api/metrics", metrics.Middleware(handleMetrics(metrics)))

	return &Server{
		httpServer: &http.Server{
			Addr:    addr,
			Handler: mux,
		},
		workerPool: wp,
		metrics:    metrics,
	}
}

func (s *Server) Start() error {
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown() error {
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	s.workerPool.Shutdown()
	return s.httpServer.Shutdown(ctx)
}

// Middleware per il worker pool
func (wp *WorkerPool) Middleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		done := make(chan struct{})
		err := wp.Submit(func(ctx context.Context) {
			defer close(done)
			select {
			case <-ctx.Done():
				http.Error(w, "richiesta cancellata", http.StatusRequestTimeout)
				return
			default:
				next(w, r.WithContext(ctx))
			}
		})
		if err != nil {
			http.Error(w, "coda piena", http.StatusServiceUnavailable)
			return
		}
		<-done
	}
}

// Middleware per le metriche
func (m *Metrics) Middleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		recorder := &responseRecorder{ResponseWriter: w, statusCode: http.StatusOK}
		next(recorder, r)
		duration := time.Since(start)
		m.RecordRequest(duration, recorder.statusCode >= 400)
	}
}

type responseRecorder struct {
	http.ResponseWriter
	statusCode int
}

func (r *responseRecorder) WriteHeader(code int) {
	r.statusCode = code
	r.ResponseWriter.WriteHeader(code)
}

// Handler per il lavoro
func handleWork(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "metodo non supportato", http.StatusMethodNotAllowed)
		return
	}

	var input struct {
		Duration string `json:"duration"`
	}
	if err := json.NewDecoder(r.Body).Decode(&input); err != nil {
		http.Error(w, "bad request", http.StatusBadRequest)
		return
	}

	dur, err := time.ParseDuration(input.Duration)
	if err != nil {
		http.Error(w, "durata non valida", http.StatusBadRequest)
		return
	}

	select {
	case <-time.After(dur):
		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "lavoro completato dopo %s", dur)
	case <-r.Context().Done():
		return
	}
}

// Handler per le metriche
func handleMetrics(metrics *Metrics) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			http.Error(w, "metodo non supportato", http.StatusMethodNotAllowed)
			return
		}
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(metrics.Snapshot())
	}
}

func main() {
	server := NewServer(":8080", 10)

	// Graceful shutdown
	go func() {
		sig := make(chan os.Signal, 1)
		signal.Notify(sig, syscall.SIGINT, syscall.SIGTERM)
		<-sig
		log.Println("shutdown in corso...")
		if err := server.Shutdown(); err != nil {
			log.Fatalf("errore durante lo shutdown: %v", err)
		}
	}()

	log.Printf("server in ascolto su %s", server.httpServer.Addr)
	if err := server.Start(); err != nil && err != http.ErrServerClosed {
		log.Fatalf("errore durante l'avvio: %v", err)
	}
	log.Println("server fermato")
}
```

Ecco i test con `httptest`:

```go
package main

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"
)

func TestServer(t *testing.T) {
	server := NewServer(":0", 5)
	ts := httptest.NewServer(server.httpServer.Handler)
	defer ts.Close()

	t.Run("work endpoint", func(t *testing.T) {
		body := map[string]string{"duration": "100ms"}
		b, _ := json.Marshal(body)
		resp, err := http.Post(ts.URL+"/api/work", "application/json", bytes.NewReader(b))
		if err != nil {
			t.Fatal(err)
		}
		if resp.StatusCode != http.StatusOK {
			t.Errorf("status atteso 200, ottenuto %d", resp.StatusCode)
		}
	})

	t.Run("work invalid duration", func(t *testing.T) {
		body := map[string]string{"duration": "invalid"}
		b, _ := json.Marshal(body)
		resp, err := http.Post(ts.URL+"/api/work", "application/json", bytes.NewReader(b))
		if err != nil {
			t.Fatal(err)
		}
		if resp.StatusCode != http.StatusBadRequest {
			t.Errorf("status atteso 400, ottenuto %d", resp.StatusCode)
		}
	})

	t.Run("work wrong method", func(t *testing.T) {
		resp, err := http.Get(ts.URL + "/api/work")
		if err != nil {
			t.Fatal(err)
		}
		if resp.StatusCode != http.StatusMethodNotAllowed {
			t.Errorf("status atteso 405, ottenuto %d", resp.StatusCode)
		}
	})

	t.Run("metrics endpoint", func(t *testing.T) {
		resp, err := http.Get(ts.URL + "/api/metrics")
		if err != nil {
			t.Fatal(err)
		}
		if resp.StatusCode != http.StatusOK {
			t.Errorf("status atteso 200, ottenuto %d", resp.StatusCode)
		}
		var metrics map[string]interface{}
		if err := json.NewDecoder(resp.Body).Decode(&metrics); err != nil {
			t.Fatal(err)
		}
		if _, ok := metrics["requests"]; !ok {
			t.Error("campo requests mancante")
		}
	})

	t.Run("worker pool full", func(t *testing.T) {
		// Invia molte richieste per riempire la coda
		for i := 0; i < 10; i++ {
			body := map[string]string{"duration": "50ms"}
			b, _ := json.Marshal(body)
			resp, err := http.Post(ts.URL+"/api/work", "application/json", bytes.NewReader(b))
			if err != nil {
				t.Fatal(err)
			}
			if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusServiceUnavailable {
				t.Errorf("status inaspettato: %d", resp.StatusCode)
			}
		}
	})

	t.Run("context cancellation", func(t *testing.T) {
		body := map[string]string{"duration": "2s"}
		b, _ := json.Marshal(body)
		req, _ := http.NewRequest(http.MethodPost, ts.URL+"/api/work", bytes.NewReader(b))
		ctx, cancel := context.WithTimeout(req.Context(), 100*time.Millisecond)
		defer cancel()
		req = req.WithContext(ctx)
		resp, err := http.DefaultClient.Do(req)
		if err != nil {
			t.Fatal(err)
		}
		if resp.StatusCode != http.StatusRequestTimeout {
			t.Errorf("status atteso 408, ottenuto %d", resp.StatusCode)
		}
	})
}
```

**Caratteristiche implementate:**

1. **Worker pool bounded**: Pool di 10 worker con coda di 100 task
2. **Context cancellation**: I worker controllano il contesto prima di eseguire i task
3. **Graceful shutdown**: Gestione dei segnali SIGINT/SIGTERM con timeout di 10 secondi
4. **Metriche base**: Conteggio richieste, errori e latenza dell'ultima richiesta
5. **Test con httptest**: Copertura completa degli endpoint e dei casi limite

**Come eseguire:**

```bash
go run main.go
# In un altro terminale:
curl -X POST http://localhost:8080/api/work -d '{"duration":"100ms"}'
curl http://localhost:8080/api/metrics
# Per testare:
go test -v
```
